function copy(enText, zhText) {
  return state.language === "zh" ? zhText : enText;
}

function phrase(enText, zhText, values = {}) {
  const template = copy(enText, zhText);
  return String(template).replace(/\\{(\\w+)\\}/g, (_, key) => String(values[key] ?? ""));
}

