function localizeBoolean(value) {
  return value ? copy("yes", "是") : copy("no", "否");
}

function parseListField(raw) {
  const out = [];
  const seen = new Set();
  String(raw || "")
    .split(/[,，\\s]+/)
    .map((value) => value.trim().toLowerCase())
    .filter(Boolean)
    .forEach((value) => {
      if (!seen.has(value)) {
        seen.add(value);
        out.push(value);
      }
    });
  return out;
}

function formatListField(values) {
  if (!Array.isArray(values)) {
    return "";
  }
  return values.filter(Boolean).join(", ");
}

function toggleListValue(raw, value) {
  const current = parseListField(raw);
  const target = String(value || "").trim().toLowerCase();
  if (!target) {
    return formatListField(current);
  }
  const idx = current.indexOf(target);
  if (idx >= 0) {
    current.splice(idx, 1);
  } else {
    current.push(target);
  }
  return formatListField(current);
}
